content.content:
     1вҶ’/**
     2вҶ’ * XState Viewport Machine POC
     3вҶ’ *
     4вҶ’ * Demonstrates the viewport state machine with visual state transitions.
     5вҶ’ * Shows zoom, pan, LOD changes with real-time state inspection.
     6вҶ’ */
     7вҶ’
     8вҶ’import React, { useRef, useMemo, useCallback } from 'react';
     9вҶ’import type { Meta, StoryObj } from '@storybook/react';
    10вҶ’import { useMachine } from '@xstate/react';
    11вҶ’import { Card, Tag, Intent, Button, ButtonGroup, Divider } from '@blueprintjs/core';
    12вҶ’import { viewportMachine } from '../../machines/viewport.machine';
    13вҶ’import { LOD_THRESHOLDS, COLORS, TIME_RANGE, TOTAL_TRAINS } from '../../data/mock-config';
    14вҶ’
    15вҶ’// =============================================================================
    16вҶ’// COMPONENT
    17вҶ’// =============================================================================
    18вҶ’
    19вҶ’interface ViewportVisualizerProps {
    20вҶ’  showStateInspector?: boolean;
    21вҶ’}
    22вҶ’
    23вҶ’function ViewportVisualizer({ showStateInspector = true }: ViewportVisualizerProps) {
    24вҶ’  const [snapshot, send] = useMachine(viewportMachine);
    25вҶ’  const containerRef = useRef<HTMLDivElement>(null);
    26вҶ’  const animationFrameRef = useRef<number | null>(null);
    27вҶ’
    28вҶ’  const context = snapshot.context;
    29вҶ’  const stateName = snapshot.value as string;
    30вҶ’
    31вҶ’  // Animation loop for momentum/animation states
    32вҶ’  const tick = useCallback(() => {
    33вҶ’    const timestamp = performance.now();
    34вҶ’
    35вҶ’    if (stateName === 'momentum') {
    36вҶ’      send({ type: 'MOMENTUM_TICK', timestamp });
    37вҶ’    } else if (stateName === 'animating') {
    38вҶ’      send({ type: 'ANIMATION_TICK', timestamp });
    39вҶ’    }
    40вҶ’
    41вҶ’    animationFrameRef.current = requestAnimationFrame(tick);
    42вҶ’  }, [send, stateName]);
    43вҶ’
    44вҶ’  // Start/stop animation loop based on state
    45вҶ’  React.useEffect(() => {
    46вҶ’    if (stateName === 'momentum' || stateName === 'animating') {
    47вҶ’      animationFrameRef.current = requestAnimationFrame(tick);
    48вҶ’    }
    49вҶ’    return () => {
    50вҶ’      if (animationFrameRef.current) {
    51вҶ’        cancelAnimationFrame(animationFrameRef.current);
    52вҶ’      }
    53вҶ’    };
    54вҶ’  }, [stateName, tick]);
    55вҶ’
    56вҶ’  // Handle wheel for zoom
    57вҶ’  const handleWheel = useCallback((e: React.WheelEvent) => {
    58вҶ’    e.preventDefault();
    59вҶ’    const rect = containerRef.current?.getBoundingClientRect();
    60вҶ’    if (!rect) return;
    61вҶ’
    62вҶ’    // Convert screen coords to world coords (simplified)
    63вҶ’    const centerX = (e.clientX - rect.left) / rect.width * TIME_RANGE.days;
    64вҶ’    const centerY = (e.clientY - rect.top) / rect.height * TOTAL_TRAINS;
    65вҶ’
    66вҶ’    send({ type: 'ZOOM', delta: e.deltaY, centerX, centerY });
    67вҶ’  }, [send]);
    68вҶ’
    69вҶ’  // Handle pointer for pan
    70вҶ’  const handlePointerDown = useCallback((e: React.PointerEvent) => {
    71вҶ’    if (e.button !== 0) return;
    72вҶ’    send({ type: 'PAN_START', pointerX: e.clientX, pointerY: e.clientY });
    73вҶ’  }, [send]);
    74вҶ’
    75вҶ’  const handlePointerMove = useCallback((e: React.PointerEvent) => {
    76вҶ’    if (stateName === 'panning') {
    77вҶ’      send({ type: 'PAN_MOVE', pointerX: e.clientX, pointerY: e.clientY });
    78вҶ’    }
    79вҶ’  }, [send, stateName]);
    80вҶ’
    81вҶ’  const handlePointerUp = useCallback(() => {
    82вҶ’    if (stateName === 'panning') {
    83вҶ’      send({ type: 'PAN_END' });
    84вҶ’    }
    85вҶ’  }, [send, stateName]);
    86вҶ’
    87вҶ’  // Handle double-click for zoom
    88вҶ’  const handleDoubleClick = useCallback((e: React.MouseEvent) => {
    89вҶ’    const rect = containerRef.current?.getBoundingClientRect();
    90вҶ’    if (!rect) return;
    91вҶ’
    92вҶ’    const x = (e.clientX - rect.left) / rect.width * TIME_RANGE.days;
    93вҶ’    const y = (e.clientY - rect.top) / rect.height * TOTAL_TRAINS;
    94вҶ’
    95вҶ’    send({ type: 'DOUBLE_TAP', x, y });
    96вҶ’  }, [send]);
    97вҶ’
    98вҶ’  // LOD indicator colors
    99вҶ’  const lodIntent = useMemo((): Intent => {
   100вҶ’    switch (context.lod) {
   101вҶ’      case 'strategic': return Intent.PRIMARY;
   102вҶ’      case 'tactical': return Intent.SUCCESS;
   103вҶ’      case 'operational': return Intent.WARNING;
   104вҶ’      case 'execution': return Intent.DANGER;
   105вҶ’    }
   106вҶ’  }, [context.lod]);
   107вҶ’
   108вҶ’  // State indicator colors
   109вҶ’  const stateIntent = useMemo((): Intent => {
   110вҶ’    switch (stateName) {
   111вҶ’      case 'idle': return Intent.NONE;
   112вҶ’      case 'panning': return Intent.PRIMARY;
   113вҶ’      case 'pinching': return Intent.SUCCESS;
   114вҶ’      case 'momentum': return Intent.WARNING;
   115вҶ’      case 'animating': return Intent.DANGER;
   116вҶ’      default: return Intent.NONE;
   117вҶ’    }
   118вҶ’  }, [stateName]);
   119вҶ’
   120вҶ’  // Viewport preview
   121вҶ’  const viewportPreviewStyle = useMemo(() => {
   122вҶ’    const scale = 1 / context.zoom;
   123вҶ’    const translateX = -context.panX / TIME_RANGE.days * 100;
   124вҶ’    const translateY = -context.panY / TOTAL_TRAINS * 100;
   125вҶ’    return {
   126вҶ’      transform: `translate(${translateX}%, ${translateY}%) scale(${scale})`,
   127вҶ’      transformOrigin: 'top left',
   128вҶ’    };
   129вҶ’  }, [context.zoom, context.panX, context.panY]);
   130вҶ’
   131вҶ’  return (
   132вҶ’    <div style={{ display: 'flex', gap: '16px', height: '100%', minHeight: '600px' }}>
   133вҶ’      {/* Canvas Area */}
   134вҶ’      <Card
   135вҶ’        style={{
   136вҶ’          flex: 2,
   137вҶ’          display: 'flex',
   138вҶ’          flexDirection: 'column',
   139вҶ’          padding: 0,
   140вҶ’          overflow: 'hidden',
   141вҶ’        }}
   142вҶ’      >
   143вҶ’        {/* Header */}
   144вҶ’        <div
   145вҶ’          style={{
   146вҶ’            padding: '12px 16px',
   147вҶ’            borderBottom: `1px solid ${COLORS.border.default}`,
   148вҶ’            display: 'flex',
   149вҶ’            alignItems: 'center',
   150вҶ’            gap: '12px',
   151вҶ’          }}
   152вҶ’        >
   153вҶ’          <Tag intent={stateIntent} large>
   154вҶ’            State: {stateName.toUpperCase()}
   155вҶ’          </Tag>
   156вҶ’          <Tag intent={lodIntent} large>
   157вҶ’            LOD: {context.lod.toUpperCase()}
   158вҶ’          </Tag>
   159вҶ’          <Tag minimal large>
   160вҶ’            Zoom: {(context.zoom * 100).toFixed(0)}%
   161вҶ’          </Tag>
   162вҶ’          <div style={{ flex: 1 }} />
   163вҶ’          <ButtonGroup>
   164вҶ’            <Button
   165вҶ’              icon="zoom-in"
   166вҶ’              onClick={() => send({ type: 'ZOOM_TO', zoom: context.zoom * 1.5, animate: true })}
   167вҶ’            />
   168вҶ’            <Button
   169вҶ’              icon="zoom-out"
   170вҶ’              onClick={() => send({ type: 'ZOOM_TO', zoom: context.zoom / 1.5, animate: true })}
   171вҶ’            />
   172вҶ’            <Button icon="home" onClick={() => send({ type: 'RESET' })} />
   173вҶ’            <Button icon="calendar" onClick={() => send({ type: 'JUMP_TO_TODAY' })}>
   174вҶ’              Today
   175вҶ’            </Button>
   176вҶ’          </ButtonGroup>
   177вҶ’        </div>
   178вҶ’
   179вҶ’        {/* Canvas */}
   180вҶ’        <div
   181вҶ’          ref={containerRef}
   182вҶ’          style={{
   183вҶ’            flex: 1,
   184вҶ’            position: 'relative',
   185вҶ’            cursor: stateName === 'panning' ? 'grabbing' : 'grab',
   186вҶ’            background: COLORS.bg.secondary,
   187вҶ’            overflow: 'hidden',
   188вҶ’          }}
   189вҶ’          onWheel={handleWheel}
   190вҶ’          onPointerDown={handlePointerDown}
   191вҶ’          onPointerMove={handlePointerMove}
   192вҶ’          onPointerUp={handlePointerUp}
   193вҶ’          onPointerLeave={handlePointerUp}
   194вҶ’          onDoubleClick={handleDoubleClick}
   195вҶ’        >
   196вҶ’          {/* Viewport visualization */}
   197вҶ’          <div
   198вҶ’            style={{
   199вҶ’              position: 'absolute',
   200вҶ’              top: '10%',
   201вҶ’              left: '10%',
   202вҶ’              width: '80%',
   203вҶ’              height: '80%',
   204вҶ’              background: COLORS.bg.primary,
   205вҶ’              border: `2px solid ${COLORS.border.strong}`,
   206вҶ’              borderRadius: '8px',
   207вҶ’              ...viewportPreviewStyle,
   208вҶ’            }}
   209вҶ’          >
   210вҶ’            {/* Grid */}
   211вҶ’            <svg width="100%" height="100%" style={{ position: 'absolute' }}>
   212вҶ’              {/* Vertical lines (time) */}
   213вҶ’              {Array.from({ length: 13 }, (_, i) => (
   214вҶ’                <line
   215вҶ’                  key={`v-${i}`}
   216вҶ’                  x1={`${(i / 12) * 100}%`}
   217вҶ’                  y1="0"
   218вҶ’                  x2={`${(i / 12) * 100}%`}
   219вҶ’                  y2="100%"
   220вҶ’                  stroke={COLORS.border.default}
   221вҶ’                  strokeWidth={i === 0 || i === 12 ? 2 : 1}
   222вҶ’                />
   223вҶ’              ))}
   224вҶ’              {/* Horizontal lines (trains) */}
   225вҶ’              {Array.from({ length: 5 }, (_, i) => (
   226вҶ’                <line
   227вҶ’                  key={`h-${i}`}
   228вҶ’                  x1="0"
   229вҶ’                  y1={`${(i / 4) * 100}%`}
   230вҶ’                  x2="100%"
   231вҶ’                  y2={`${(i / 4) * 100}%`}
   232вҶ’                  stroke={COLORS.border.default}
   233вҶ’                  strokeWidth={i === 0 || i === 4 ? 2 : 1}
   234вҶ’                />
   235вҶ’              ))}
   236вҶ’              {/* LOD-specific visualization */}
   237вҶ’              {context.lod === 'strategic' && (
   238вҶ’                <rect
   239вҶ’                  x="10%"
   240вҶ’                  y="20%"
   241вҶ’                  width="80%"
   242вҶ’                  height="60%"
   243вҶ’                  fill={COLORS.heatmap.medium}
   244вҶ’                  opacity={0.5}
   245вҶ’                />
   246вҶ’              )}
   247вҶ’              {context.lod === 'tactical' && (
   248вҶ’                <>
   249вҶ’                  {Array.from({ length: 12 }, (_, i) => (
   250вҶ’                    <rect
   251вҶ’                      key={i}
   252вҶ’                      x={`${10 + i * 6.5}%`}
   253вҶ’                      y={`${30 + Math.random() * 20}%`}
   254вҶ’                      width="5%"
   255вҶ’                      height={`${20 + Math.random() * 30}%`}
   256вҶ’                      fill={COLORS.status.info}
   257вҶ’                      opacity={0.7}
   258вҶ’                    />
   259вҶ’                  ))}
   260вҶ’                </>
   261вҶ’              )}
   262вҶ’              {(context.lod === 'operational' || context.lod === 'execution') && (
   263вҶ’                <>
   264вҶ’                  {Array.from({ length: 8 }, (_, i) => (
   265вҶ’                    <rect
   266вҶ’                      key={i}
   267вҶ’                      x={`${15 + i * 10}%`}
   268вҶ’                      y={`${25 + i * 5}%`}
   269вҶ’                      width={`${5 + Math.random() * 10}%`}
   270вҶ’                      height="8%"
   271вҶ’                      fill={['#60a5fa', '#a78bfa', '#f472b6', '#fb923c'][i % 4]}
   272вҶ’                      rx="4"
   273вҶ’                    />
   274вҶ’                  ))}
   275вҶ’                </>
   276вҶ’              )}
   277вҶ’            </svg>
   278вҶ’
   279вҶ’            {/* LOD label */}
   280вҶ’            <div
   281вҶ’              style={{
   282вҶ’                position: 'absolute',
   283вҶ’                top: '50%',
   284вҶ’                left: '50%',
   285вҶ’                transform: 'translate(-50%, -50%)',
   286вҶ’                fontSize: '24px',
   287вҶ’                fontWeight: 'bold',
   288вҶ’                color: COLORS.text.muted,
   289вҶ’                opacity: 0.5,
   290вҶ’              }}
   291вҶ’            >
   292вҶ’              {context.lod.toUpperCase()} VIEW
   293вҶ’            </div>
   294вҶ’          </div>
   295вҶ’
   296вҶ’          {/* Zoom level indicator */}
   297вҶ’          <div
   298вҶ’            style={{
   299вҶ’              position: 'absolute',
   300вҶ’              bottom: '16px',
   301вҶ’              right: '16px',
   302вҶ’              background: COLORS.bg.primary,
   303вҶ’              padding: '8px 16px',
   304вҶ’              borderRadius: '4px',
   305вҶ’              boxShadow: '0 2px 8px rgba(0,0,0,0.1)',
   306вҶ’              fontSize: '14px',
   307вҶ’              fontFamily: 'monospace',
   308вҶ’            }}
   309вҶ’          >
   310вҶ’            {context.zoom.toFixed(2)}x
   311вҶ’          </div>
   312вҶ’
   313вҶ’          {/* LOD thresholds indicator */}
   314вҶ’          <div
   315вҶ’            style={{
   316вҶ’              position: 'absolute',
   317вҶ’              bottom: '16px',
   318вҶ’              left: '16px',
   319вҶ’              background: COLORS.bg.primary,
   320вҶ’              padding: '8px 12px',
   321вҶ’              borderRadius: '4px',
   322вҶ’              boxShadow: '0 2px 8px rgba(0,0,0,0.1)',
   323вҶ’              fontSize: '12px',
   324вҶ’            }}
   325вҶ’          >
   326вҶ’            <div style={{ display: 'flex', gap: '8px', alignItems: 'center' }}>
   327вҶ’              <span
   328вҶ’                style={{
   329вҶ’                  width: '8px',
   330вҶ’                  height: '8px',
   331вҶ’                  borderRadius: '50%',
   332вҶ’                  background: context.lod === 'strategic' ? COLORS.status.info : COLORS.border.default,
   333вҶ’                }}
   334вҶ’              />
   335вҶ’              <span>&lt;{LOD_THRESHOLDS.strategic}x Strategic</span>
   336вҶ’            </div>
   337вҶ’            <div style={{ display: 'flex', gap: '8px', alignItems: 'center', marginTop: '4px' }}>
   338вҶ’              <span
   339вҶ’                style={{
   340вҶ’                  width: '8px',
   341вҶ’                  height: '8px',
   342вҶ’                  borderRadius: '50%',
   343вҶ’                  background: context.lod === 'tactical' ? COLORS.status.healthy : COLORS.border.default,
   344вҶ’                }}
   345вҶ’              />
   346вҶ’              <span>&lt;{LOD_THRESHOLDS.tactical}x Tactical</span>
   347вҶ’            </div>
   348вҶ’            <div style={{ display: 'flex', gap: '8px', alignItems: 'center', marginTop: '4px' }}>
   349вҶ’              <span
   350вҶ’                style={{
   351вҶ’                  width: '8px',
   352вҶ’                  height: '8px',
   353вҶ’                  borderRadius: '50%',
   354вҶ’                  background: context.lod === 'operational' ? COLORS.status.warning : COLORS.border.default,
   355вҶ’                }}
   356вҶ’              />
   357вҶ’              <span>&lt;{LOD_THRESHOLDS.operational}x Operational</span>
   358вҶ’            </div>
   359вҶ’            <div style={{ display: 'flex', gap: '8px', alignItems: 'center', marginTop: '4px' }}>
   360вҶ’              <span
   361вҶ’                style={{
   362вҶ’                  width: '8px',
   363вҶ’                  height: '8px',
   364вҶ’                  borderRadius: '50%',
   365вҶ’                  background: context.lod === 'execution' ? COLORS.status.critical : COLORS.border.default,
   366вҶ’                }}
   367вҶ’              />
   368вҶ’              <span>вүҘ{LOD_THRESHOLDS.operational}x Execution</span>
   369вҶ’            </div>
   370вҶ’          </div>
   371вҶ’        </div>
   372вҶ’      </Card>
   373вҶ’
   374вҶ’      {/* State Inspector */}
   375вҶ’      {showStateInspector && (
   376вҶ’        <Card style={{ flex: 1, overflow: 'auto' }}>
   377вҶ’          <h3 style={{ marginTop: 0 }}>State Inspector</h3>
   378вҶ’          <Divider />
   379вҶ’
   380вҶ’          <h4>Current State</h4>
   381вҶ’          <Tag intent={stateIntent} large fill>
   382вҶ’            {stateName}
   383вҶ’          </Tag>
   384вҶ’
   385вҶ’          <h4 style={{ marginTop: '16px' }}>Context</h4>
   386вҶ’          <div style={{ fontFamily: 'monospace', fontSize: '12px' }}>
   387вҶ’            <ContextValue label="zoom" value={context.zoom.toFixed(4)} />
   388вҶ’            <ContextValue label="panX" value={context.panX.toFixed(2)} />
   389вҶ’            <ContextValue label="panY" value={context.panY.toFixed(2)} />
   390вҶ’            <Divider />
   391вҶ’            <ContextValue label="lod" value={context.lod} />
   392вҶ’            <ContextValue label="prevLod" value={context.prevLod ?? 'null'} />
   393вҶ’            <ContextValue
   394вҶ’              label="lodTransition"
   395вҶ’              value={`${(context.lodTransitionProgress * 100).toFixed(0)}%`}
   396вҶ’            />
   397вҶ’            <Divider />
   398вҶ’            <ContextValue label="velocityX" value={context.velocityX.toFixed(2)} />
   399вҶ’            <ContextValue label="velocityY" value={context.velocityY.toFixed(2)} />
   400вҶ’            <Divider />
   401вҶ’            <ContextValue label="isPinching" value={context.isPinching.toString()} />
   402вҶ’            <ContextValue label="animating" value={(stateName === 'animating').toString()} />
   403вҶ’          </div>
   404вҶ’
   405вҶ’          <h4 style={{ marginTop: '16px' }}>Quick Actions</h4>
   406вҶ’          <div style={{ display: 'flex', flexDirection: 'column', gap: '8px' }}>
   407вҶ’            <Button
   408вҶ’              fill
   409вҶ’              onClick={() => send({ type: 'ZOOM_TO', zoom: 0.2, animate: true })}
   410вҶ’            >
   411вҶ’              Strategic (0.2x)
   412вҶ’            </Button>
   413вҶ’            <Button
   414вҶ’              fill
   415вҶ’              onClick={() => send({ type: 'ZOOM_TO', zoom: 0.5, animate: true })}
   416вҶ’            >
   417вҶ’              Tactical (0.5x)
   418вҶ’            </Button>
   419вҶ’            <Button
   420вҶ’              fill
   421вҶ’              onClick={() => send({ type: 'ZOOM_TO', zoom: 1.5, animate: true })}
   422вҶ’            >
   423вҶ’              Operational (1.5x)
   424вҶ’            </Button>
   425вҶ’            <Button
   426вҶ’              fill
   427вҶ’              onClick={() => send({ type: 'ZOOM_TO', zoom: 4.0, animate: true })}
   428вҶ’            >
   429вҶ’              Execution (4x)
   430вҶ’            </Button>
   431вҶ’            <Divider />
   432вҶ’            <Button
   433вҶ’              fill
   434вҶ’              intent={Intent.PRIMARY}
   435вҶ’              onClick={() => send({ type: 'JUMP_TO_TRAIN', trainIndex: 64 })}
   436вҶ’            >
   437вҶ’              Jump to Train #64
   438вҶ’            </Button>
   439вҶ’          </div>
   440вҶ’        </Card>
   441вҶ’      )}
   442вҶ’    </div>
   443вҶ’  );
   444вҶ’}
   445вҶ’
   446вҶ’function ContextValue({ label, value }: { label: string; value: string }) {
   447вҶ’  return (
   448вҶ’    <div style={{ display: 'flex', justifyContent: 'space-between', marginBottom: '4px' }}>
   449вҶ’      <span style={{ color: COLORS.text.secondary }}>{label}:</span>
   450вҶ’      <span style={{ fontWeight: 'bold' }}>{value}</span>
   451вҶ’    </div>
   452вҶ’  );
   453вҶ’}
   454вҶ’
   455вҶ’// =============================================================================
   456вҶ’// STORY CONFIGURATION
   457вҶ’// =============================================================================
   458вҶ’
   459вҶ’const meta: Meta<typeof ViewportVisualizer> = {
   460вҶ’  title: '01-POCs/State/XStateViewport',
   461вҶ’  component: ViewportVisualizer,
   462вҶ’  parameters: {
   463вҶ’    layout: 'fullscreen',
   464вҶ’    docs: {
   465вҶ’      description: {
   466вҶ’        component: `
   467вҶ’## XState Viewport Machine
   468вҶ’
   469вҶ’This POC demonstrates the viewport state machine for the MMS Fractal Canvas.
   470вҶ’
   471вҶ’### States
   472вҶ’- **idle**: Ready for user input
   473вҶ’- **panning**: User is dragging to pan
   474вҶ’- **pinching**: User is pinch-zooming (touch)
   475вҶ’- **momentum**: Inertial panning after release
   476вҶ’- **animating**: Smooth transition to target position/zoom
   477вҶ’
   478вҶ’### LOD Levels
   479вҶ’- **Strategic** (zoom < 0.3x): 10-12 year heatmap view
   480вҶ’- **Tactical** (0.3x - 1.0x): 1-3 year workload bars
   481вҶ’- **Operational** (1.0x - 3.0x): 1-6 month Gantt view
   482вҶ’- **Execution** (> 3.0x): 1-4 week detailed tasks
   483вҶ’
   484вҶ’### Interactions
   485вҶ’- **Scroll**: Zoom in/out centered on cursor
   486вҶ’- **Drag**: Pan the viewport
   487вҶ’- **Double-click**: Zoom 2x at click position
