     1вҶ’/**
     2вҶ’ * POC: Semantic Zoom with Crossfade Transitions
     3вҶ’ *
     4вҶ’ * Demonstrates smooth LOD transitions using opacity crossfade:
     5вҶ’ * - Strategic (zoom < 0.3): Heatmap overview
     6вҶ’ * - Tactical (0.3 <= zoom < 1.0): Stacked bars
     7вҶ’ * - Operational (1.0 <= zoom < 3.0): DNA Gantt pattern
     8вҶ’ * - Execution (zoom >= 3.0): Detailed task cards
     9вҶ’ *
    10вҶ’ * Key concepts:
    11вҶ’ * 1. Each LOD layer renders independently
    12вҶ’ * 2. Crossfade opacity based on zoom proximity to threshold
    13вҶ’ * 3. Smooth 60fps transitions without jarring changes
    14вҶ’ */
    15вҶ’
    16вҶ’import React, { useState, useMemo, useCallback, useRef, useEffect } from 'react';
    17вҶ’import type { Meta, StoryObj } from '@storybook/react';
    18вҶ’import { useGesture } from '@use-gesture/react';
    19вҶ’import { Card, Tag, Intent, Divider, ProgressBar, Slider } from '@blueprintjs/core';
    20вҶ’
    21вҶ’import { COLORS, LOD_THRESHOLDS, ANIMATION, getLODLevel } from '../../data/mock-config';
    22вҶ’import type { LODLevel } from '../../data/mock-config';
    23вҶ’
    24вҶ’// =============================================================================
    25вҶ’// TYPES
    26вҶ’// =============================================================================
    27вҶ’
    28вҶ’interface ViewportState {
    29вҶ’  zoom: number;
    30вҶ’  x: number;
    31вҶ’  y: number;
    32вҶ’}
    33вҶ’
    34вҶ’interface LayerOpacities {
    35вҶ’  strategic: number;
    36вҶ’  tactical: number;
    37вҶ’  operational: number;
    38вҶ’  execution: number;
    39вҶ’}
    40вҶ’
    41вҶ’// =============================================================================
    42вҶ’// CONSTANTS
    43вҶ’// =============================================================================
    44вҶ’
    45вҶ’const CROSSFADE_RANGE = 0.15; // Opacity transition range around threshold
    46вҶ’
    47вҶ’const LOD_COLORS: Record<LODLevel, string> = {
    48вҶ’  strategic: '#3b82f6',    // blue-500
    49вҶ’  tactical: '#8b5cf6',     // violet-500
    50вҶ’  operational: '#f59e0b',  // amber-500
    51вҶ’  execution: '#10b981',    // emerald-500
    52вҶ’};
    53вҶ’
    54вҶ’const LOD_DESCRIPTIONS: Record<LODLevel, string> = {
    55вҶ’  strategic: '12-Year Heatmap Overview',
    56вҶ’  tactical: 'Quarterly Stacked Bars',
    57вҶ’  operational: 'Monthly DNA Gantt',
    58вҶ’  execution: 'Weekly Task Details',
    59вҶ’};
    60вҶ’
    61вҶ’// =============================================================================
    62вҶ’// OPACITY CALCULATION
    63вҶ’// =============================================================================
    64вҶ’
    65вҶ’/**
    66вҶ’ * Calculate layer opacities based on current zoom level.
    67вҶ’ * Uses smooth crossfade transitions near thresholds.
    68вҶ’ */
    69вҶ’function calculateLayerOpacities(zoom: number): LayerOpacities {
    70вҶ’  const { strategic, tactical, operational } = LOD_THRESHOLDS;
    71вҶ’
    72вҶ’  // Helper: smooth step function for crossfade
    73вҶ’  const smoothStep = (value: number, edge0: number, edge1: number): number => {
    74вҶ’    const t = Math.max(0, Math.min(1, (value - edge0) / (edge1 - edge0)));
    75вҶ’    return t * t * (3 - 2 * t); // Smooth Hermite interpolation
    76вҶ’  };
    77вҶ’
    78вҶ’  // Calculate fade factors for each threshold
    79вҶ’  const fadeStrategicToTactical = smoothStep(
    80вҶ’    zoom,
    81вҶ’    strategic - CROSSFADE_RANGE,
    82вҶ’    strategic + CROSSFADE_RANGE
    83вҶ’  );
    84вҶ’
    85вҶ’  const fadeTacticalToOperational = smoothStep(
    86вҶ’    zoom,
    87вҶ’    tactical - CROSSFADE_RANGE,
    88вҶ’    tactical + CROSSFADE_RANGE
    89вҶ’  );
    90вҶ’
    91вҶ’  const fadeOperationalToExecution = smoothStep(
    92вҶ’    zoom,
    93вҶ’    operational - CROSSFADE_RANGE,
    94вҶ’    operational + CROSSFADE_RANGE
    95вҶ’  );
    96вҶ’
    97вҶ’  // Calculate final opacities
    98вҶ’  return {
    99вҶ’    strategic: 1 - fadeStrategicToTactical,
   100вҶ’    tactical: fadeStrategicToTactical * (1 - fadeTacticalToOperational),
   101вҶ’    operational: fadeTacticalToOperational * (1 - fadeOperationalToExecution),
   102вҶ’    execution: fadeOperationalToExecution,
   103вҶ’  };
   104вҶ’}
   105вҶ’
   106вҶ’// =============================================================================
   107вҶ’// MOCK LOD LAYER COMPONENTS
   108вҶ’// =============================================================================
   109вҶ’
   110вҶ’interface LayerProps {
   111вҶ’  opacity: number;
   112вҶ’  zoom: number;
   113вҶ’}
   114вҶ’
   115вҶ’function StrategicLayer({ opacity, zoom }: LayerProps) {
   116вҶ’  if (opacity < 0.01) return null;
   117вҶ’
   118вҶ’  // Generate heatmap cells
   119вҶ’  const cells = useMemo(() => {
   120вҶ’    const items = [];
   121вҶ’    for (let row = 0; row < 8; row++) {
   122вҶ’      for (let col = 0; col < 12; col++) {
   123вҶ’        const intensity = Math.sin(row * 0.5 + col * 0.3) * 0.5 + 0.5;
   124вҶ’        items.push({ row, col, intensity });
   125вҶ’      }
   126вҶ’    }
   127вҶ’    return items;
   128вҶ’  }, []);
   129вҶ’
   130вҶ’  return (
   131вҶ’    <div
   132вҶ’      style={{
   133вҶ’        position: 'absolute',
   134вҶ’        inset: 0,
   135вҶ’        opacity,
   136вҶ’        transition: 'opacity 50ms ease-out',
   137вҶ’        display: 'grid',
   138вҶ’        gridTemplateColumns: 'repeat(12, 1fr)',
   139вҶ’        gridTemplateRows: 'repeat(8, 1fr)',
   140вҶ’        gap: 2,
   141вҶ’        padding: 40,
   142вҶ’      }}
   143вҶ’    >
   144вҶ’      {cells.map(({ row, col, intensity }) => (
   145вҶ’        <div
   146вҶ’          key={`${row}-${col}`}
   147вҶ’          style={{
   148вҶ’            background: `rgba(59, 130, 246, ${0.2 + intensity * 0.6})`,
   149вҶ’            borderRadius: 4,
   150вҶ’            display: 'flex',
   151вҶ’            alignItems: 'center',
   152вҶ’            justifyContent: 'center',
   153вҶ’            fontSize: 10,
   154вҶ’            color: intensity > 0.5 ? 'white' : COLORS.text.secondary,
