   470вҶ’
   471вҶ’function SemanticZoomDemo() {
   472вҶ’  const containerRef = useRef<HTMLDivElement>(null);
   473вҶ’
   474вҶ’  // Viewport state
   475вҶ’  const [viewport, setViewport] = useState<ViewportState>({
   476вҶ’    zoom: 0.15,
   477вҶ’    x: 0,
   478вҶ’    y: 0,
   479вҶ’  });
   480вҶ’
   481вҶ’  // Calculate current LOD and layer opacities
   482вҶ’  const currentLOD = useMemo(() => getLODLevel(viewport.zoom), [viewport.zoom]);
   483вҶ’  const opacities = useMemo(() => calculateLayerOpacities(viewport.zoom), [viewport.zoom]);
   484вҶ’
   485вҶ’  // Zoom change handler
   486вҶ’  const handleZoomChange = useCallback((newZoom: number) => {
   487вҶ’    setViewport((prev) => ({ ...prev, zoom: newZoom }));
   488вҶ’  }, []);
   489вҶ’
   490вҶ’  // Gesture bindings for wheel zoom
   491вҶ’  const bind = useGesture({
   492вҶ’    onWheel: ({ delta: [, dy], event }) => {
   493вҶ’      event.preventDefault();
   494вҶ’      setViewport((prev) => ({
   495вҶ’        ...prev,
   496вҶ’        zoom: Math.max(0.1, Math.min(5, prev.zoom * (1 - dy * 0.002))),
   497вҶ’      }));
   498вҶ’    },
   499вҶ’  }, {
   500вҶ’    wheel: { preventDefault: true },
   501вҶ’  });
   502вҶ’
   503вҶ’  return (
   504вҶ’    <div
   505вҶ’      ref={containerRef}
   506вҶ’      {...bind()}
   507вҶ’      style={{
   508вҶ’        width: '100%',
   509вҶ’        height: '100vh',
   510вҶ’        position: 'relative',
   511вҶ’        background: COLORS.bg.primary,
   512вҶ’        overflow: 'hidden',
   513вҶ’        touchAction: 'none',
   514вҶ’      }}
   515вҶ’    >
   516вҶ’      {/* LOD Layers with crossfade */}
   517вҶ’      <StrategicLayer opacity={opacities.strategic} zoom={viewport.zoom} />
   518вҶ’      <TacticalLayer opacity={opacities.tactical} zoom={viewport.zoom} />
   519вҶ’      <OperationalLayer opacity={opacities.operational} zoom={viewport.zoom} />
   520вҶ’      <ExecutionLayer opacity={opacities.execution} zoom={viewport.zoom} />
   521вҶ’
   522вҶ’      {/* UI Overlays */}
   523вҶ’      <InfoPanel viewport={viewport} opacities={opacities} currentLOD={currentLOD} />
   524вҶ’      <ZoomControl zoom={viewport.zoom} onZoomChange={handleZoomChange} />
   525вҶ’    </div>
   526вҶ’  );
   527вҶ’}
