    11вҶ’
    12вҶ’// =============================================================================
    13вҶ’// TYPES
    14вҶ’// =============================================================================
    15вҶ’
    16вҶ’export interface ViewportContext {
    17вҶ’  // Camera position
    18вҶ’  zoom: number;
    19вҶ’  panX: number; // World X (time axis, in days)
    20вҶ’  panY: number; // World Y (train axis, in train indices)
    21вҶ’
    22вҶ’  // LOD state
    23вҶ’  lod: LODLevel;
    24вҶ’  prevLod: LODLevel | null;
    25вҶ’  lodTransitionProgress: number; // 0-1 for crossfade
    26вҶ’
    27вҶ’  // Viewport dimensions
    28вҶ’  viewportWidth: number;
    29вҶ’  viewportHeight: number;
    30вҶ’
    31вҶ’  // Animation state
    32вҶ’  targetZoom: number | null;
    33вҶ’  targetPanX: number | null;
    34вҶ’  targetPanY: number | null;
    35вҶ’  animationStartTime: number | null;
    36вҶ’  animationDuration: number;
    37вҶ’  animationStartZoom: number;
    38вҶ’  animationStartPanX: number;
    39вҶ’  animationStartPanY: number;
    40вҶ’
    41вҶ’  // Momentum state (for inertial panning)
    42вҶ’  velocityX: number;
    43вҶ’  velocityY: number;
    44вҶ’
    45вҶ’  // Interaction state
    46вҶ’  isPinching: boolean;
    47вҶ’  pinchStartZoom: number;
    48вҶ’  pointerStartX: number;
    49вҶ’  pointerStartY: number;
    50вҶ’  panStartX: number;
    51вҶ’  panStartY: number;
    52вҶ’}
    53вҶ’
    54вҶ’export type ViewportEvent =
    55вҶ’  | { type: 'ZOOM'; delta: number; centerX: number; centerY: number }
    56вҶ’  | { type: 'ZOOM_TO'; zoom: number; centerX?: number; centerY?: number; animate?: boolean }
    57вҶ’  | { type: 'PAN'; deltaX: number; deltaY: number }
    58вҶ’  | { type: 'PAN_TO'; x: number; y: number; animate?: boolean }
    59вҶ’  | { type: 'PAN_START'; pointerX: number; pointerY: number }
    60вҶ’  | { type: 'PAN_MOVE'; pointerX: number; pointerY: number }
    61вҶ’  | { type: 'PAN_END'; velocityX?: number; velocityY?: number }
    62вҶ’  | { type: 'PINCH_START'; zoom: number }
    63вҶ’  | { type: 'PINCH_MOVE'; scale: number; centerX: number; centerY: number }
    64вҶ’  | { type: 'PINCH_END' }
    65вҶ’  | { type: 'DOUBLE_TAP'; x: number; y: number }
    66вҶ’  | { type: 'RESET' }
    67вҶ’  | { type: 'JUMP_TO_TODAY' }
    68вҶ’  | { type: 'JUMP_TO_TRAIN'; trainIndex: number }
    69вҶ’  | { type: 'ANIMATION_TICK'; timestamp: number }
    70вҶ’  | { type: 'MOMENTUM_TICK'; timestamp: number }
    71вҶ’  | { type: 'LOD_TRANSITION_COMPLETE' }
    72вҶ’  | { type: 'RESIZE'; width: number; height: number };
    73вҶ’
    74вҶ’// =============================================================================
    75вҶ’// CONSTANTS
    76вҶ’// =============================================================================
    77вҶ’
    78вҶ’const MIN_ZOOM = 0.1;
    79вҶ’const MAX_ZOOM = 10;
    80вҶ’const ZOOM_SENSITIVITY = 0.002;
    81вҶ’const DOUBLE_TAP_ZOOM_FACTOR = 2;
    82вҶ’const MOMENTUM_FRICTION = 0.92;
    83вҶ’const MOMENTUM_MIN_VELOCITY = 0.5;
    84вҶ’
    85вҶ’// World bounds
    86вҶ’const WORLD_MIN_X = 0;
    87вҶ’const WORLD_MAX_X = TIME_RANGE.days; // 4383 days
    88вҶ’const WORLD_MIN_Y = 0;
    89вҶ’const WORLD_MAX_Y = TOTAL_TRAINS; // 128 trains
    90вҶ’
    91вҶ’// =============================================================================
    92вҶ’// HELPER FUNCTIONS
    93вҶ’// =============================================================================
    94вҶ’
    95вҶ’function getLODLevel(zoom: number): LODLevel {
    96вҶ’  if (zoom < LOD_THRESHOLDS.strategic) return 'strategic';
    97вҶ’  if (zoom < LOD_THRESHOLDS.tactical) return 'tactical';
    98вҶ’  if (zoom < LOD_THRESHOLDS.operational) return 'operational';
    99вҶ’  return 'execution';
   100вҶ’}
   101вҶ’
   102вҶ’function clamp(value: number, min: number, max: number): number {
   103вҶ’  return Math.max(min, Math.min(max, value));
   104вҶ’}
   105вҶ’
   106вҶ’function clampZoom(zoom: number): number {
   107вҶ’  return clamp(zoom, MIN_ZOOM, MAX_ZOOM);
   108вҶ’}
   109вҶ’
   110вҶ’function clampPan(x: number, y: number): { x: number; y: number } {
   111вҶ’  return {
   112вҶ’    x: clamp(x, WORLD_MIN_X, WORLD_MAX_X),
   113вҶ’    y: clamp(y, WORLD_MIN_Y, WORLD_MAX_Y),
   114вҶ’  };
   115вҶ’}
   116вҶ’
   117вҶ’// Ease out expo for smooth animations
   118вҶ’function easeOutExpo(t: number): number {
   119вҶ’  return t === 1 ? 1 : 1 - Math.pow(2, -10 * t);
   120вҶ’}
   121вҶ’
   122вҶ’// Get "today" position in days from start
   123вҶ’function getTodayDayIndex(): number {
   124вҶ’  const today = new Date();
   125вҶ’  const start = TIME_RANGE.start;
   126вҶ’  const diffMs = today.getTime() - start.getTime();
   127вҶ’  const diffDays = Math.floor(diffMs / (1000 * 60 * 60 * 24));
   128вҶ’  return clamp(diffDays, 0, TIME_RANGE.days);
   129вҶ’}
   130вҶ’
   131вҶ’// =============================================================================
   132вҶ’// INITIAL CONTEXT
   133вҶ’// =============================================================================
   134вҶ’
   135вҶ’const initialContext: ViewportContext = {
   136вҶ’  zoom: 0.2, // Start at strategic level
   137вҶ’  panX: 0,
   138вҶ’  panY: TOTAL_TRAINS / 2, // Center on trains
   139вҶ’
   140вҶ’  lod: 'strategic',
   141вҶ’  prevLod: null,
   142вҶ’  lodTransitionProgress: 1,
   143вҶ’
   144вҶ’  viewportWidth: 1200,
   145вҶ’  viewportHeight: 800,
   146вҶ’
   147вҶ’  targetZoom: null,
   148вҶ’  targetPanX: null,
   149вҶ’  targetPanY: null,
   150вҶ’  animationStartTime: null,
   151вҶ’  animationDuration: ANIMATION.duration.zoom,
   152вҶ’  animationStartZoom: 0.2,
   153вҶ’  animationStartPanX: 0,
   154вҶ’  animationStartPanY: TOTAL_TRAINS / 2,
   155вҶ’
   156вҶ’  velocityX: 0,
   157вҶ’  velocityY: 0,
   158вҶ’
   159вҶ’  isPinching: false,
   160вҶ’  pinchStartZoom: 1,
   161вҶ’  pointerStartX: 0,
   162вҶ’  pointerStartY: 0,
   163вҶ’  panStartX: 0,
   164вҶ’  panStartY: 0,
   165вҶ’};
   166вҶ’
   167вҶ’// =============================================================================
   168вҶ’// STATE MACHINE
   169вҶ’// =============================================================================
   170вҶ’
   171вҶ’export const viewportMachine = createMachine({
   172вҶ’  id: 'viewport',
   173вҶ’  initial: 'idle',
   174вҶ’  context: initialContext,
   175вҶ’  states: {
   176вҶ’    idle: {
   177вҶ’      on: {
   178вҶ’        ZOOM: {
   179вҶ’          actions: assign(({ context, event }) => {
   180вҶ’            const zoomFactor = 1 - event.delta * ZOOM_SENSITIVITY;
   181вҶ’            const newZoom = clampZoom(context.zoom * zoomFactor);
   182вҶ’
   183вҶ’            // Zoom toward cursor position
   184вҶ’            const zoomRatio = newZoom / context.zoom;
   185вҶ’            const newPanX = event.centerX - (event.centerX - context.panX) * zoomRatio;
   186вҶ’            const newPanY = event.centerY - (event.centerY - context.panY) * zoomRatio;
   187вҶ’            const clamped = clampPan(newPanX, newPanY);
   188вҶ’
   189вҶ’            const newLod = getLODLevel(newZoom);
   190вҶ’            const lodChanged = newLod !== context.lod;
   191вҶ’
   192вҶ’            return {
   193вҶ’              zoom: newZoom,
   194вҶ’              panX: clamped.x,
   195вҶ’              panY: clamped.y,
   196вҶ’              lod: newLod,
   197вҶ’              prevLod: lodChanged ? context.lod : context.prevLod,
   198вҶ’              lodTransitionProgress: lodChanged ? 0 : context.lodTransitionProgress,
   199вҶ’            };
   200вҶ’          }),
   201вҶ’        },
   202вҶ’        ZOOM_TO: {
   203вҶ’          target: 'animating',
   204вҶ’          actions: assign(({ context, event }) => ({
   205вҶ’            targetZoom: clampZoom(event.zoom),
   206вҶ’            targetPanX: event.centerX ?? context.panX,
   207вҶ’            targetPanY: event.centerY ?? context.panY,
   208вҶ’            animationStartTime: performance.now(),
   209вҶ’            animationDuration: event.animate === false ? 0 : ANIMATION.duration.zoom,
   210вҶ’            animationStartZoom: context.zoom,
   211вҶ’            animationStartPanX: context.panX,
   212вҶ’            animationStartPanY: context.panY,
   213вҶ’          })),
   214вҶ’        },
   215вҶ’        PAN: {
   216вҶ’          actions: assign(({ context, event }) => {
   217вҶ’            const clamped = clampPan(
   218вҶ’              context.panX - event.deltaX / context.zoom,
   219вҶ’              context.panY - event.deltaY / context.zoom
   220вҶ’            );
   221вҶ’            return {
   222вҶ’              panX: clamped.x,
   223вҶ’              panY: clamped.y,
   224вҶ’            };
   225вҶ’          }),
   226вҶ’        },
   227вҶ’        PAN_START: {
   228вҶ’          target: 'panning',
   229вҶ’          actions: assign(({ context, event }) => ({
   230вҶ’            pointerStartX: event.pointerX,
   231вҶ’            pointerStartY: event.pointerY,
   232вҶ’            panStartX: context.panX,
   233вҶ’            panStartY: context.panY,
   234вҶ’            velocityX: 0,
   235вҶ’            velocityY: 0,
   236вҶ’          })),
   237вҶ’        },
   238вҶ’        PAN_TO: {
   239вҶ’          target: 'animating',
   240вҶ’          actions: assign(({ context, event }) => ({
   241вҶ’            targetZoom: context.zoom,
   242вҶ’            targetPanX: event.x,
   243вҶ’            targetPanY: event.y,
   244вҶ’            animationStartTime: performance.now(),
   245вҶ’            animationDuration: event.animate === false ? 0 : ANIMATION.duration.zoom,
   246вҶ’            animationStartZoom: context.zoom,
   247вҶ’            animationStartPanX: context.panX,
   248вҶ’            animationStartPanY: context.panY,
   249вҶ’          })),
   250вҶ’        },
   251вҶ’        PINCH_START: {
   252вҶ’          target: 'pinching',
   253вҶ’          actions: assign(({ context, event }) => ({
   254вҶ’            isPinching: true,
   255вҶ’            pinchStartZoom: context.zoom,
   256вҶ’          })),
   257вҶ’        },
   258вҶ’        DOUBLE_TAP: {
   259вҶ’          target: 'animating',
   260вҶ’          actions: assign(({ context, event }) => {
   261вҶ’            const newZoom = clampZoom(context.zoom * DOUBLE_TAP_ZOOM_FACTOR);
   262вҶ’            return {
   263вҶ’              targetZoom: newZoom,
   264вҶ’              targetPanX: event.x,
   265вҶ’              targetPanY: event.y,
   266вҶ’              animationStartTime: performance.now(),
   267вҶ’              animationDuration: ANIMATION.duration.zoom,
   268вҶ’              animationStartZoom: context.zoom,
   269вҶ’              animationStartPanX: context.panX,
   270вҶ’              animationStartPanY: context.panY,
   271вҶ’            };
   272вҶ’          }),
   273вҶ’        },
   274вҶ’        RESET: {
   275вҶ’          target: 'animating',
   276вҶ’          actions: assign(({ context }) => ({
   277вҶ’            targetZoom: initialContext.zoom,
   278вҶ’            targetPanX: initialContext.panX,
   279вҶ’            targetPanY: initialContext.panY,
   280вҶ’            animationStartTime: performance.now(),
   281вҶ’            animationDuration: ANIMATION.duration.zoom,
   282вҶ’            animationStartZoom: context.zoom,
   283вҶ’            animationStartPanX: context.panX,
   284вҶ’            animationStartPanY: context.panY,
   285вҶ’          })),
   286вҶ’        },
   287вҶ’        JUMP_TO_TODAY: {
   288вҶ’          target: 'animating',
   289вҶ’          actions: assign(({ context }) => ({
   290вҶ’            targetZoom: 1.0, // Tactical level
   291вҶ’            targetPanX: getTodayDayIndex(),
   292вҶ’            targetPanY: context.panY,
   293вҶ’            animationStartTime: performance.now(),
   294вҶ’            animationDuration: ANIMATION.duration.zoom,
   295вҶ’            animationStartZoom: context.zoom,
   296вҶ’            animationStartPanX: context.panX,
   297вҶ’            animationStartPanY: context.panY,
   298вҶ’          })),
   299вҶ’        },
   300вҶ’        JUMP_TO_TRAIN: {
   301вҶ’          target: 'animating',
   302вҶ’          actions: assign(({ context, event }) => ({
   303вҶ’            targetZoom: context.zoom,
   304вҶ’            targetPanX: context.panX,
   305вҶ’            targetPanY: event.trainIndex,
   306вҶ’            animationStartTime: performance.now(),
   307вҶ’            animationDuration: ANIMATION.duration.zoom,
   308вҶ’            animationStartZoom: context.zoom,
   309вҶ’            animationStartPanX: context.panX,
   310вҶ’            animationStartPanY: context.panY,
   311вҶ’          })),
   312вҶ’        },
   313вҶ’        RESIZE: {
   314вҶ’          actions: assign(({ event }) => ({
   315вҶ’            viewportWidth: event.width,
   316вҶ’            viewportHeight: event.height,
   317вҶ’          })),
   318вҶ’        },
   319вҶ’        LOD_TRANSITION_COMPLETE: {
   320вҶ’          actions: assign(() => ({
   321вҶ’            lodTransitionProgress: 1,
   322вҶ’            prevLod: null,
   323вҶ’          })),
   324вҶ’        },
   325вҶ’      },
   326вҶ’    },
   327вҶ’    panning: {
   328вҶ’      on: {
   329вҶ’        PAN_MOVE: {
   330вҶ’          actions: assign(({ context, event }) => {
   331вҶ’            const deltaX = (event.pointerX - context.pointerStartX) / context.zoom;
   332вҶ’            const deltaY = (event.pointerY - context.pointerStartY) / context.zoom;
   333вҶ’            const clamped = clampPan(
   334вҶ’              context.panStartX - deltaX,
   335вҶ’              context.panStartY - deltaY
   336вҶ’            );
   337вҶ’
   338вҶ’            // Calculate velocity for momentum
   339вҶ’            const velocityX = (context.panX - clamped.x) * 0.5;
   340вҶ’            const velocityY = (context.panY - clamped.y) * 0.5;
   341вҶ’
   342вҶ’            return {
   343вҶ’              panX: clamped.x,
   344вҶ’              panY: clamped.y,
   345вҶ’              velocityX,
   346вҶ’              velocityY,
   347вҶ’            };
   348вҶ’          }),
   349вҶ’        },
   350вҶ’        PAN_END: [
   351вҶ’          {
   352вҶ’            target: 'momentum',
   353вҶ’            guard: ({ context }) =>
   354вҶ’              Math.abs(context.velocityX) > MOMENTUM_MIN_VELOCITY ||
   355вҶ’              Math.abs(context.velocityY) > MOMENTUM_MIN_VELOCITY,
   356вҶ’          },
   357вҶ’          {
   358вҶ’            target: 'idle',
   359вҶ’          },
   360вҶ’        ],
   361вҶ’        ZOOM: {
   362вҶ’          actions: assign(({ context, event }) => {
   363вҶ’            const zoomFactor = 1 - event.delta * ZOOM_SENSITIVITY;
   364вҶ’            const newZoom = clampZoom(context.zoom * zoomFactor);
   365вҶ’            const newLod = getLODLevel(newZoom);
   366вҶ’            const lodChanged = newLod !== context.lod;
   367вҶ’
   368вҶ’            return {
   369вҶ’              zoom: newZoom,
   370вҶ’              lod: newLod,
   371вҶ’              prevLod: lodChanged ? context.lod : context.prevLod,
   372вҶ’              lodTransitionProgress: lodChanged ? 0 : context.lodTransitionProgress,
   373вҶ’            };
   374вҶ’          }),
   375вҶ’        },
   376вҶ’      },
   377вҶ’    },
   378вҶ’    pinching: {
   379вҶ’      on: {
   380вҶ’        PINCH_MOVE: {
   381вҶ’          actions: assign(({ context, event }) => {
   382вҶ’            const newZoom = clampZoom(context.pinchStartZoom * event.scale);
   383вҶ’
   384вҶ’            // Zoom toward pinch center
   385вҶ’            const zoomRatio = newZoom / context.zoom;
   386вҶ’            const newPanX = event.centerX - (event.centerX - context.panX) * zoomRatio;
   387вҶ’            const newPanY = event.centerY - (event.centerY - context.panY) * zoomRatio;
   388вҶ’            const clamped = clampPan(newPanX, newPanY);
   389вҶ’
   390вҶ’            const newLod = getLODLevel(newZoom);
   391вҶ’            const lodChanged = newLod !== context.lod;
   392вҶ’
   393вҶ’            return {
   394вҶ’              zoom: newZoom,
   395вҶ’              panX: clamped.x,
   396вҶ’              panY: clamped.y,
   397вҶ’              lod: newLod,
   398вҶ’              prevLod: lodChanged ? context.lod : context.prevLod,
   399вҶ’              lodTransitionProgress: lodChanged ? 0 : context.lodTransitionProgress,
   400вҶ’            };
   401вҶ’          }),
   402вҶ’        },
   403вҶ’        PINCH_END: {
   404вҶ’          target: 'idle',
   405вҶ’          actions: assign(() => ({
   406вҶ’            isPinching: false,
   407вҶ’          })),
   408вҶ’        },
   409вҶ’      },
   410вҶ’    },
   411вҶ’    momentum: {
   412вҶ’      on: {
   413вҶ’        MOMENTUM_TICK: [
   414вҶ’          {
   415вҶ’            target: 'idle',
   416вҶ’            guard: ({ context }) =>
   417вҶ’              Math.abs(context.velocityX) < MOMENTUM_MIN_VELOCITY &&
   418вҶ’              Math.abs(context.velocityY) < MOMENTUM_MIN_VELOCITY,
   419вҶ’          },
   420вҶ’          {
   421вҶ’            actions: assign(({ context }) => {
   422вҶ’              const clamped = clampPan(
   423вҶ’                context.panX + context.velocityX,
   424вҶ’                context.panY + context.velocityY
   425вҶ’              );
   426вҶ’              return {
   427вҶ’                panX: clamped.x,
   428вҶ’                panY: clamped.y,
   429вҶ’                velocityX: context.velocityX * MOMENTUM_FRICTION,
   430вҶ’                velocityY: context.velocityY * MOMENTUM_FRICTION,
   431вҶ’              };
   432вҶ’            }),
   433вҶ’          },
   434вҶ’        ],
   435вҶ’        PAN_START: {
   436вҶ’          target: 'panning',
   437вҶ’          actions: assign(({ context, event }) => ({
   438вҶ’            pointerStartX: event.pointerX,
   439вҶ’            pointerStartY: event.pointerY,
   440вҶ’            panStartX: context.panX,
   441вҶ’            panStartY: context.panY,
   442вҶ’            velocityX: 0,
   443вҶ’            velocityY: 0,
   444вҶ’          })),
   445вҶ’        },
   446вҶ’        ZOOM: {
   447вҶ’          target: 'idle',
   448вҶ’          actions: assign(({ context, event }) => {
   449вҶ’            const zoomFactor = 1 - event.delta * ZOOM_SENSITIVITY;
   450вҶ’            const newZoom = clampZoom(context.zoom * zoomFactor);
   451вҶ’            const newLod = getLODLevel(newZoom);
   452вҶ’
   453вҶ’            return {
   454вҶ’              zoom: newZoom,
   455вҶ’              lod: newLod,
   456вҶ’              velocityX: 0,
   457вҶ’              velocityY: 0,
   458вҶ’            };
   459вҶ’          }),
   460вҶ’        },
   461вҶ’      },
   462вҶ’    },
   463вҶ’    animating: {
   464вҶ’      on: {
   465вҶ’        ANIMATION_TICK: [
   466вҶ’          {
   467вҶ’            target: 'idle',
   468вҶ’            guard: ({ context, event }) => {
   469вҶ’              if (!context.animationStartTime) return true;
   470вҶ’              const elapsed = event.timestamp - context.animationStartTime;
   471вҶ’              return elapsed >= context.animationDuration;
   472вҶ’            },
   473вҶ’            actions: assign(({ context }) => {
   474вҶ’              const finalZoom = context.targetZoom ?? context.animationStartZoom;
   475вҶ’              const finalPanX = context.targetPanX ?? context.animationStartPanX;
   476вҶ’              const finalPanY = context.targetPanY ?? context.animationStartPanY;
   477вҶ’              const newLod = getLODLevel(finalZoom);
   478вҶ’              const lodChanged = newLod !== context.lod;
   479вҶ’
   480вҶ’              return {
   481вҶ’                zoom: finalZoom,
   482вҶ’                panX: finalPanX,
   483вҶ’                panY: finalPanY,
   484вҶ’                lod: newLod,
   485вҶ’                prevLod: lodChanged ? context.lod : null,
   486вҶ’                lodTransitionProgress: lodChanged ? 0 : 1,
   487вҶ’                targetZoom: null,
   488вҶ’                targetPanX: null,
   489вҶ’                targetPanY: null,
   490вҶ’                animationStartTime: null,
   491вҶ’              };
   492вҶ’            }),
   493вҶ’          },
   494вҶ’          {
   495вҶ’            actions: assign(({ context, event }) => {
   496вҶ’              if (!context.animationStartTime) return {};
   497вҶ’
   498вҶ’              const elapsed = event.timestamp - context.animationStartTime;
   499вҶ’              const progress = Math.min(1, elapsed / context.animationDuration);
   500вҶ’              const eased = easeOutExpo(progress);
   501вҶ’
   502вҶ’              const startZoom = context.animationStartZoom;
   503вҶ’              const startPanX = context.animationStartPanX;
   504вҶ’              const startPanY = context.animationStartPanY;
   505вҶ’              const targetZoom = context.targetZoom ?? startZoom;
   506вҶ’              const targetPanX = context.targetPanX ?? startPanX;
   507вҶ’              const targetPanY = context.targetPanY ?? startPanY;
   508вҶ’
   509вҶ’              const newZoom = startZoom + (targetZoom - startZoom) * eased;
   510вҶ’              const newPanX = startPanX + (targetPanX - startPanX) * eased;
   511вҶ’              const newPanY = startPanY + (targetPanY - startPanY) * eased;
   512вҶ’
   513вҶ’              const newLod = getLODLevel(newZoom);
   514вҶ’
   515вҶ’              return {
   516вҶ’                zoom: newZoom,
   517вҶ’                panX: newPanX,
   518вҶ’                panY: newPanY,
   519вҶ’                lod: newLod,
   520вҶ’              };
   521вҶ’            }),
   522вҶ’          },
   523вҶ’        ],
   524вҶ’        PAN_START: {
   525вҶ’          target: 'panning',
   526вҶ’          actions: assign(({ context, event }) => ({
   527вҶ’            // Cancel animation
   528вҶ’            targetZoom: null,
   529вҶ’            targetPanX: null,
   530вҶ’            targetPanY: null,
   531вҶ’            animationStartTime: null,
   532вҶ’            // Start panning
   533вҶ’            pointerStartX: event.pointerX,
   534вҶ’            pointerStartY: event.pointerY,
   535вҶ’            panStartX: context.panX,
   536вҶ’            panStartY: context.panY,
   537вҶ’            velocityX: 0,
   538вҶ’            velocityY: 0,
   539вҶ’          })),
   540вҶ’        },
   541вҶ’      },
   542вҶ’    },
   543вҶ’  },
   544вҶ’});
   545вҶ’
   546вҶ’// =============================================================================
   547вҶ’// EXPORTS
   548вҶ’// =============================================================================
   549вҶ’
   550вҶ’export type ViewportMachine = typeof viewportMachine;
   551вҶ’export type ViewportState = ReturnType<typeof viewportMachine.getInitialSnapshot>;
   552вҶ’

