    80вҶ’
    81вҶ’// Seeded random for reproducibility
    82вҶ’let seed = 12345;
    83вҶ’
    84вҶ’function seededRandom(): number {
    85вҶ’  seed = (seed * 1103515245 + 12345) & 0x7fffffff;
    86вҶ’  return seed / 0x7fffffff;
    87вҶ’}
    88вҶ’
    89вҶ’function resetSeed(newSeed: number = 12345): void {
    90вҶ’  seed = newSeed;
    91вҶ’}
    92вҶ’
    93вҶ’function randomInRange(min: number, max: number): number {
    94вҶ’  return min + seededRandom() * (max - min);
    95вҶ’}
    96вҶ’
    97вҶ’function randomInt(min: number, max: number): number {
    98вҶ’  return Math.floor(randomInRange(min, max + 1));
    99вҶ’}
   100вҶ’
   101вҶ’function randomChoice<T>(arr: T[]): T {
   102вҶ’  return arr[Math.floor(seededRandom() * arr.length)];
   103вҶ’}
   104вҶ’
   105вҶ’// =============================================================================
   106вҶ’// DATE UTILITIES
   107вҶ’// =============================================================================
   108вҶ’
   109вҶ’function addDays(date: Date, days: number): Date {
   110вҶ’  const result = new Date(date);
   111вҶ’  result.setDate(result.getDate() + days);
   112вҶ’  return result;
   113вҶ’}
   114вҶ’
   115вҶ’function addHours(date: Date, hours: number): Date {
   116вҶ’  const result = new Date(date);
   117вҶ’  result.setTime(result.getTime() + hours * 60 * 60 * 1000);
   118вҶ’  return result;
   119вҶ’}
   120вҶ’
   121вҶ’function daysBetween(start: Date, end: Date): number {
   122вҶ’  return Math.floor((end.getTime() - start.getTime()) / (1000 * 60 * 60 * 24));
   123вҶ’}
   124вҶ’
   125вҶ’function getQuarterIndex(date: Date): number {
   126вҶ’  const year = date.getFullYear() - 2024;
   127вҶ’  const quarter = Math.floor(date.getMonth() / 3);
   128вҶ’  return year * 4 + quarter;
   129вҶ’}
   130вҶ’
   131вҶ’function getMonthIndex(date: Date): number {
   132вҶ’  const year = date.getFullYear() - 2024;
   133вҶ’  const month = date.getMonth();
   134вҶ’  return year * 12 + month;
   135вҶ’}
   136вҶ’
   137вҶ’// =============================================================================
   138вҶ’// TRAIN GENERATION
   139вҶ’// =============================================================================
   140вҶ’
   141вҶ’function generateTrains(): Train[] {
   142вҶ’  const trains: Train[] = [];
   143вҶ’  let globalIndex = 0;
   144вҶ’
   145вҶ’  for (const fleet of FLEETS) {
   146вҶ’    for (let i = 0; i < fleet.count; i++) {
   147вҶ’      const trainNumber = String(i + 1).padStart(3, '0');
   148вҶ’      const avgDailyMileage = MILEAGE.average_daily_km * (1 + randomInRange(-MILEAGE.variance, MILEAGE.variance));
   149вҶ’
   150вҶ’      // Initial mileage: trains have been running since before 2024
   151вҶ’      // Assume 1-5 years of prior operation
   152вҶ’      const priorYears = randomInRange(1, 5);
   153вҶ’      const initialMileage = avgDailyMileage * 365 * priorYears;
   154вҶ’
   155вҶ’      trains.push({
   156вҶ’        id: `${fleet.prefix}-${trainNumber}`,
   157вҶ’        name: `${fleet.name} ${trainNumber}`,
   158вҶ’        fleetId: fleet.id,
   159вҶ’        fleetName: fleet.name,
   160вҶ’        index: globalIndex,
   161вҶ’        currentMileageKm: Math.round(initialMileage),
   162вҶ’        avgDailyMileageKm: Math.round(avgDailyMileage),
   163вҶ’      });
   164вҶ’      globalIndex++;
   165вҶ’    }
   166вҶ’  }
   167вҶ’
   168вҶ’  return trains;
   169вҶ’}
   170вҶ’
   171вҶ’// =============================================================================
   172вҶ’// TASK GENERATION
   173вҶ’// =============================================================================
   174вҶ’
   175вҶ’function generateTasksForTrain(train: Train, taskIdCounter: { value: number }): Task[] {
   176вҶ’  const tasks: Task[] = [];
   177вҶ’  let currentMileage = train.currentMileageKm;
   178вҶ’  let currentDate = new Date(TIME_RANGE.start);
   179вҶ’
   180вҶ’  // Track next maintenance due for each type
   181вҶ’  const nextDue: Record<MaintenanceTypeId, number> = {
   182вҶ’    pm1: currentMileage + MAINTENANCE_TYPES[0].interval_km,
   183вҶ’    pm2: currentMileage + MAINTENANCE_TYPES[1].interval_km,
   184вҶ’    pm3: currentMileage + MAINTENANCE_TYPES[2].interval_km,
   185вҶ’    overhaul: currentMileage + MAINTENANCE_TYPES[3].interval_km,
   186вҶ’    corrective: 0, // Random
   187вҶ’  };
   188вҶ’
   189вҶ’  // Simulate day by day through 12 years
   190вҶ’  while (currentDate < TIME_RANGE.end) {
   191вҶ’    // Accumulate daily mileage with variance
   192вҶ’    const dailyVariance = 1 + randomInRange(-0.1, 0.1);
   193вҶ’    const todayMileage = train.avgDailyMileageKm * dailyVariance;
   194вҶ’    currentMileage += todayMileage;
   195вҶ’
   196вҶ’    // Check for scheduled maintenance triggers
   197вҶ’    const typesToSchedule: MaintenanceTypeId[] = [];
   198вҶ’
   199вҶ’    // Check each maintenance type (except corrective)
   200вҶ’    for (const mt of MAINTENANCE_TYPES.slice(0, 4)) {
   201вҶ’      if (currentMileage >= nextDue[mt.id]) {
   202вҶ’        typesToSchedule.push(mt.id);
   203вҶ’        // Reset next due
   204вҶ’        nextDue[mt.id] = currentMileage + mt.interval_km;
   205вҶ’      }
   206вҶ’    }
   207вҶ’
   208вҶ’    // Random corrective maintenance (~2% daily chance when not in other maintenance)
   209вҶ’    if (typesToSchedule.length === 0 && seededRandom() < 0.02) {
   210вҶ’      typesToSchedule.push('corrective');
   211вҶ’    }
   212вҶ’
   213вҶ’    // Schedule tasks
   214вҶ’    for (const typeId of typesToSchedule) {
   215вҶ’      const mt = MAINTENANCE_TYPE_MAP.get(typeId)!;
   216вҶ’
   217вҶ’      // Add some scheduling variance (Вұ3 days)
   218вҶ’      const scheduledDate = addDays(currentDate, randomInt(-3, 7));
   219вҶ’
   220вҶ’      // Don't schedule in the past
   221вҶ’      if (scheduledDate < TIME_RANGE.start) continue;
   222вҶ’
   223вҶ’      // Don't schedule after end date
   224вҶ’      if (scheduledDate >= TIME_RANGE.end) continue;
   225вҶ’
   226вҶ’      const endDate = addHours(scheduledDate, mt.duration_hours);
   227вҶ’
   228вҶ’      // Determine status based on date relative to "today" (mid-2030 for demo)
   229вҶ’      const today = new Date('2030-06-15');
   230вҶ’      let status: TaskStatus = 'scheduled';
   231вҶ’
   232вҶ’      if (scheduledDate < today) {
   233вҶ’        if (endDate < today) {
   234вҶ’          status = seededRandom() < 0.95 ? 'completed' : 'overdue';
   235вҶ’        } else {
   236вҶ’          status = 'in-progress';
   237вҶ’        }
   238вҶ’      }
   239вҶ’
   240вҶ’      // Some tasks have conflicts (~8%)
   241вҶ’      const hasConflict = seededRandom() < 0.08;
   242вҶ’      if (hasConflict) {
   243вҶ’        status = 'conflict';
   244вҶ’      }
   245вҶ’
   246вҶ’      const task: Task = {
   247вҶ’        id: `TASK-${String(taskIdCounter.value++).padStart(6, '0')}`,
   248вҶ’        trainId: train.id,
   249вҶ’        trainIndex: train.index,
   250вҶ’        type: typeId,
   251вҶ’        name: mt.name,
   252вҶ’        startDate: scheduledDate,
   253вҶ’        endDate: endDate,
   254вҶ’        durationHours: mt.duration_hours,
   255вҶ’        manHours: mt.man_hours,
   256вҶ’        costAed: mt.cost_aed,
   257вҶ’        status,
   258вҶ’        pitId: randomInt(1, RESOURCES.pits),
   259вҶ’        technicians: Math.ceil(mt.man_hours / 8),
   260вҶ’        partsReady: seededRandom() < 0.85,
   261вҶ’        hasConflict,
   262вҶ’        color: mt.color,
   263вҶ’      };
   264вҶ’
   265вҶ’      tasks.push(task);
   266вҶ’    }
   267вҶ’
   268вҶ’    // Advance one day
   269вҶ’    currentDate = addDays(currentDate, 1);
   270вҶ’  }
   271вҶ’
   272вҶ’  return tasks;
   273вҶ’}
   274вҶ’
   275вҶ’// =============================================================================
   276вҶ’// AGGREGATION
   277вҶ’// =============================================================================
   278вҶ’
   279вҶ’function aggregateByQuarter(trains: Train[], tasks: Task[]): AggregatedCell[] {
   280вҶ’  const cells: AggregatedCell[] = [];
   281вҶ’  const cellMap = new Map<string, AggregatedCell>();
   282вҶ’
   283вҶ’  // Initialize all cells
   284вҶ’  for (let trainIndex = 0; trainIndex < trains.length; trainIndex++) {
   285вҶ’    for (let quarterIndex = 0; quarterIndex < TIME_RANGE.quarters; quarterIndex++) {
   286вҶ’      const key = `${trainIndex}-${quarterIndex}`;
   287вҶ’      const cell: AggregatedCell = {
   288вҶ’        trainIndex,
   289вҶ’        periodIndex: quarterIndex,
   290вҶ’        totalTasks: 0,
   291вҶ’        totalManHours: 0,
   292вҶ’        totalCostAed: 0,
   293вҶ’        tasksByType: { pm1: 0, pm2: 0, pm3: 0, overhaul: 0, corrective: 0 },
   294вҶ’        hasOverhaul: false,
   295вҶ’        utilizationPercent: 0,
   296вҶ’      };
   297вҶ’      cellMap.set(key, cell);
   298вҶ’    }
   299вҶ’  }
   300вҶ’
   301вҶ’  // Aggregate tasks
   302вҶ’  for (const task of tasks) {
   303вҶ’    const quarterIndex = getQuarterIndex(task.startDate);
   304вҶ’    if (quarterIndex < 0 || quarterIndex >= TIME_RANGE.quarters) continue;
   305вҶ’
   306вҶ’    const key = `${task.trainIndex}-${quarterIndex}`;
   307вҶ’    const cell = cellMap.get(key);
   308вҶ’    if (!cell) continue;
   309вҶ’
   310вҶ’    cell.totalTasks++;
   311вҶ’    cell.totalManHours += task.manHours;
   312вҶ’    cell.totalCostAed += task.costAed;
   313вҶ’    cell.tasksByType[task.type]++;
   314вҶ’    if (task.type === 'overhaul') {
   315вҶ’      cell.hasOverhaul = true;
   316вҶ’    }
   317вҶ’  }
   318вҶ’
   319вҶ’  // Calculate utilization
   320вҶ’  const maxManHoursPerQuarter = RESOURCES.max_manhours_per_month * 3; // 6000
   321вҶ’  for (const cell of cellMap.values()) {
   322вҶ’    cell.utilizationPercent = Math.min(100, (cell.totalManHours / maxManHoursPerQuarter) * 100);
   323вҶ’    cells.push(cell);
   324вҶ’  }
   325вҶ’
   326вҶ’  return cells;
   327вҶ’}
   328вҶ’
   329вҶ’function aggregateByMonth(trains: Train[], tasks: Task[]): AggregatedCell[] {
   330вҶ’  const cells: AggregatedCell[] = [];
   331вҶ’  const cellMap = new Map<string, AggregatedCell>();
   332вҶ’
   333вҶ’  // Initialize all cells
   334вҶ’  for (let trainIndex = 0; trainIndex < trains.length; trainIndex++) {
   335вҶ’    for (let monthIndex = 0; monthIndex < TIME_RANGE.months; monthIndex++) {
   336вҶ’      const key = `${trainIndex}-${monthIndex}`;
   337вҶ’      const cell: AggregatedCell = {
   338вҶ’        trainIndex,
   339вҶ’        periodIndex: monthIndex,
   340вҶ’        totalTasks: 0,
   341вҶ’        totalManHours: 0,
   342вҶ’        totalCostAed: 0,
   343вҶ’        tasksByType: { pm1: 0, pm2: 0, pm3: 0, overhaul: 0, corrective: 0 },
   344вҶ’        hasOverhaul: false,
   345вҶ’        utilizationPercent: 0,
   346вҶ’      };
   347вҶ’      cellMap.set(key, cell);
   348вҶ’    }
   349вҶ’  }
   350вҶ’
   351вҶ’  // Aggregate tasks
   352вҶ’  for (const task of tasks) {
   353вҶ’    const monthIndex = getMonthIndex(task.startDate);
   354вҶ’    if (monthIndex < 0 || monthIndex >= TIME_RANGE.months) continue;
   355вҶ’
   356вҶ’    const key = `${task.trainIndex}-${monthIndex}`;
   357вҶ’    const cell = cellMap.get(key);
   358вҶ’    if (!cell) continue;
   359вҶ’
   360вҶ’    cell.totalTasks++;
   361вҶ’    cell.totalManHours += task.manHours;
   362вҶ’    cell.totalCostAed += task.costAed;
   363вҶ’    cell.tasksByType[task.type]++;
   364вҶ’    if (task.type === 'overhaul') {
   365вҶ’      cell.hasOverhaul = true;
   366вҶ’    }
   367вҶ’  }
   368вҶ’
   369вҶ’  // Calculate utilization
   370вҶ’  const maxManHoursPerMonth = RESOURCES.max_manhours_per_month; // 2000
   371вҶ’  for (const cell of cellMap.values()) {
   372вҶ’    cell.utilizationPercent = Math.min(100, (cell.totalManHours / maxManHoursPerMonth) * 100);
   373вҶ’    cells.push(cell);
   374вҶ’  }
   375вҶ’
   376вҶ’  return cells;
   377вҶ’}
   378вҶ’
   379вҶ’// =============================================================================
   380вҶ’// MAIN GENERATOR
   381вҶ’// =============================================================================
   382вҶ’
   383вҶ’let cachedData: MockData | null = null;
   384вҶ’
   385вҶ’export function generateMockData(forceRegenerate: boolean = false): MockData {
   386вҶ’  if (cachedData && !forceRegenerate) {
   387вҶ’    return cachedData;
   388вҶ’  }
   389вҶ’
   390вҶ’  console.time('generateMockData');
   391вҶ’  resetSeed(12345);
   392вҶ’
   393вҶ’  // Generate trains
   394вҶ’  const trains = generateTrains();
   395вҶ’  console.log(`Generated ${trains.length} trains`);
   396вҶ’
   397вҶ’  // Generate tasks for each train
   398вҶ’  const taskIdCounter = { value: 1 };
   399вҶ’  const allTasks: Task[] = [];
   400вҶ’
   401вҶ’  for (const train of trains) {
   402вҶ’    const trainTasks = generateTasksForTrain(train, taskIdCounter);
   403вҶ’    allTasks.push(...trainTasks);
   404вҶ’  }
   405вҶ’
   406вҶ’  // Sort tasks by date
   407вҶ’  allTasks.sort((a, b) => a.startDate.getTime() - b.startDate.getTime());
   408вҶ’  console.log(`Generated ${allTasks.length} tasks`);
   409вҶ’
   410вҶ’  // Aggregate data
   411вҶ’  const aggregatedByQuarter = aggregateByQuarter(trains, allTasks);
   412вҶ’  const aggregatedByMonth = aggregateByMonth(trains, allTasks);
   413вҶ’  console.log(`Aggregated: ${aggregatedByQuarter.length} quarterly cells, ${aggregatedByMonth.length} monthly cells`);
   414вҶ’
   415вҶ’  // Calculate stats
   416вҶ’  const conflictCount = allTasks.filter(t => t.hasConflict).length;
   417вҶ’  const totalManHours = allTasks.reduce((sum, t) => sum + t.manHours, 0);
   418вҶ’  const totalCostAed = allTasks.reduce((sum, t) => sum + t.costAed, 0);
   419вҶ’
   420вҶ’  const data: MockData = {
   421вҶ’    trains,
   422вҶ’    tasks: allTasks,
   423вҶ’    aggregatedByQuarter,
   424вҶ’    aggregatedByMonth,
   425вҶ’    stats: {
   426вҶ’      totalTrains: trains.length,
   427вҶ’      totalTasks: allTasks.length,
   428вҶ’      totalManHours,
   429вҶ’      totalCostAed,
   430вҶ’      avgTasksPerTrain: Math.round(allTasks.length / trains.length),
   431вҶ’      conflictCount,
   432вҶ’    },
   433вҶ’  };
   434вҶ’
   435вҶ’  console.timeEnd('generateMockData');
   436вҶ’  console.log('Stats:', data.stats);
   437вҶ’
   438вҶ’  cachedData = data;
   439вҶ’  return data;
   440вҶ’}
   441вҶ’
   442вҶ’// =============================================================================
