   445вҶ’
   446вҶ’export function getTasksInRange(data: MockData, startDate: Date, endDate: Date): Task[] {
   447вҶ’  return data.tasks.filter(
   448вҶ’    t => t.startDate >= startDate && t.startDate <= endDate
   449вҶ’  );
