   452вҶ’export function getTasksForTrain(data: MockData, trainId: string): Task[] {
   453вҶ’  return data.tasks.filter(t => t.trainId === trainId);
   454вҶ’}
   455вҶ’
   456вҶ’export function getTasksForTrainInRange(
   457вҶ’  data: MockData,
   458вҶ’  trainId: string,
   459вҶ’  startDate: Date,
   460вҶ’  endDate: Date
   461вҶ’): Task[] {
   462вҶ’  return data.tasks.filter(
   463вҶ’    t => t.trainId === trainId && t.startDate >= startDate && t.startDate <= endDate
   464вҶ’  );
   465вҶ’}
   466вҶ’
   467вҶ’export function getAggregatedCellsForViewport(
   468вҶ’  cells: AggregatedCell[],
   469вҶ’  trainIndexStart: number,
   470вҶ’  trainIndexEnd: number,
