    71вҶ’
    72вҶ’function getLODLevel(zoom: number): LODLevel {
    73вҶ’  if (zoom < LOD_THRESHOLDS.strategic.max) return 'strategic';
    74вҶ’  if (zoom < LOD_THRESHOLDS.tactical.max) return 'tactical';
    75вҶ’  if (zoom < LOD_THRESHOLDS.operational.max) return 'operational';
