   265вҶ’    }
   266вҶ’
   267вҶ’    const taskPolygons: TaskPolygon[] = mockData.tasks.map((task) => {
   268вҶ’      const startDay = daysBetween(TIME_RANGE.start, task.startDate);
   269вҶ’      const duration = Math.max(1, daysBetween(task.startDate, task.endDate));
   270вҶ’
   271вҶ’      const x = startDay * OPERATIONAL_PX_PER_DAY;
   272вҶ’      const y = task.trainIndex * OPERATIONAL_PX_PER_TRAIN + 4;
   273вҶ’      const w = duration * OPERATIONAL_PX_PER_DAY - 1;
   274вҶ’      const h = 20;
   275вҶ’
   276вҶ’      const mt = MAINTENANCE_TYPE_MAP.get(task.type);
   277вҶ’      const baseColor = mt?.color ?? COLORS.task.default;
   278вҶ’
   279вҶ’      return {
   280вҶ’        polygon: [
   281вҶ’          [x, y],
   282вҶ’          [x + w, y],
   283вҶ’          [x + w, y + h],
   284вҶ’          [x, y + h],
   285вҶ’        ],
   286вҶ’        task,
   287вҶ’        color: hexToRgba(baseColor, 255 * opacities.operational),
   288вҶ’      };
   289вҶ’    });
   290вҶ’
   291вҶ’    return [
   292вҶ’      // Background rows
   293вҶ’      new SolidPolygonLayer<{ polygon: [number, number][]; index: number }>({
   294вҶ’        id: 'operational-grid',
   295вҶ’        data: mockData.trains.map((_, i) => ({
   296вҶ’          polygon: [
   297вҶ’            [0, i * OPERATIONAL_PX_PER_TRAIN],
   298вҶ’            [worldDimensions.operational.width, i * OPERATIONAL_PX_PER_TRAIN],
   299вҶ’            [worldDimensions.operational.width, (i + 1) * OPERATIONAL_PX_PER_TRAIN - 1],
   300вҶ’            [0, (i + 1) * OPERATIONAL_PX_PER_TRAIN - 1],
   301вҶ’          ],
   302вҶ’          index: i,
   303вҶ’        })),
   304вҶ’        getPolygon: (d) => d.polygon,
   305вҶ’        getFillColor: (d) => d.index % 2 === 0
   306вҶ’          ? [250, 250, 250, 255 * opacities.operational]
   307вҶ’          : [245, 245, 245, 255 * opacities.operational],
   308вҶ’        pickable: false,
   309вҶ’        opacity: opacities.operational * 0.8,
   310вҶ’      }),
   311вҶ’      // Task bars
   312вҶ’      new SolidPolygonLayer<TaskPolygon>({
   313вҶ’        id: 'operational-tasks',
   314вҶ’        data: taskPolygons,
   315вҶ’        getPolygon: (d) => d.polygon,
   316вҶ’        getFillColor: (d) => {
   317вҶ’          if (d.task.hasConflict) return [239, 68, 68, 255 * opacities.operational];
   318вҶ’          return d.color;
   319вҶ’        },
   320вҶ’        pickable: true,
   321вҶ’        opacity: opacities.operational,
   322вҶ’        updateTriggers: {
   323вҶ’          getFillColor: [opacities.operational],
   324вҶ’        },
   325вҶ’      }),
   326вҶ’    ];
   327вҶ’  }, [mockData.tasks, mockData.trains.length, worldDimensions.operational.width, opacities.operational]);
   328вҶ’
   329вҶ’  // All deck.gl layers
   330вҶ’  const layers = useMemo(() => [
   331вҶ’    ...strategicLayers,
   332вҶ’    ...tacticalLayers,
   333вҶ’    ...operationalLayers,
   334вҶ’  ], [strategicLayers, tacticalLayers, operationalLayers]);
   335вҶ’
   336вҶ’  // View state - calculate target based on current LOD's world dimensions
   337вҶ’  const viewState: ViewState = useMemo(() => {
   338вҶ’    // Calculate world dimensions for current LOD
   339вҶ’    let worldWidth: number;
   340вҶ’    let worldHeight: number;
   341вҶ’
   342вҶ’    if (currentLOD === 'strategic') {
   343вҶ’      worldWidth = worldDimensions.strategic.width;
   344вҶ’      worldHeight = worldDimensions.strategic.height;
   345вҶ’    } else if (currentLOD === 'tactical') {
   346вҶ’      worldWidth = worldDimensions.tactical.width;
   347вҶ’      worldHeight = worldDimensions.tactical.height;
   348вҶ’    } else {
   349вҶ’      worldWidth = worldDimensions.operational.width;
   350вҶ’      worldHeight = worldDimensions.operational.height;
   351вҶ’    }
   352вҶ’
   353вҶ’    // Calculate scale factor from zoom
   354вҶ’    const scale = Math.pow(2, Math.log2(zoom));
   355вҶ’
   356вҶ’    // Calculate viewport size in world coordinates
   357вҶ’    const viewportWidth = (width - 100) / scale;
   358вҶ’    const viewportHeight = (height - 40) / scale;
   359вҶ’
   360вҶ’    // Center target - start at center of visible data, offset by camera position
   361вҶ’    const targetX = viewportWidth / 2 + cameraX * (worldWidth / mockData.trains.length);
   362вҶ’    const targetY = viewportHeight / 2 + cameraY * (worldHeight / mockData.trains.length);
   363вҶ’
   364вҶ’    return {
   365вҶ’      target: [targetX, targetY, 0],
   366вҶ’      zoom: Math.log2(zoom),
   367вҶ’    };
   368вҶ’  }, [cameraX, cameraY, zoom, width, height, currentLOD, worldDimensions, mockData.trains.length]);
   369вҶ’
   370вҶ’  // Handle zoom change
   371вҶ’  const handleZoomChange = useCallback((delta: number) => {
   372вҶ’    setZoom((z) => Math.max(0.1, Math.min(5, z + delta)));
   373вҶ’  }, []);
   374вҶ’
   375вҶ’  // Handle pan
   376вҶ’  const handlePan = useCallback((dx: number, dy: number) => {
   377вҶ’    setCameraX((x) => x + dx);
   378вҶ’    setCameraY((y) => Math.max(0, Math.min(mockData.trains.length - 1, y + dy)));
   379вҶ’  }, [mockData.trains.length]);
   380вҶ’
   381вҶ’  // View - memoize to prevent recreation on every render
   382вҶ’  const views = useMemo(() => new OrthographicView({
   383вҶ’    id: 'fractal-view',
   384вҶ’    flipY: false,
   385вҶ’    controller: true,
   386вҶ’  }), []);
   387вҶ’
   388вҶ’  // Get visible trains based on cameraY
   389вҶ’  const visibleTrains = useMemo(() => {
   390вҶ’    const startIndex = Math.max(0, Math.floor(cameraY));
   391вҶ’    const visibleCount = Math.ceil(height / 30) + 2;
   392вҶ’    return mockData.trains.slice(startIndex, startIndex + visibleCount);
   393вҶ’  }, [cameraY, height, mockData.trains]);
   394вҶ’
   395вҶ’  return (
   396вҶ’    <div style={{ width, height, position: 'relative', background: '#f4f4f5' }}>
   397вҶ’      {/* Navbar */}
   398вҶ’      <Navbar style={{ height: 40 }}>
   399вҶ’        <NavbarGroup align={Alignment.LEFT}>
   400вҶ’          <NavbarHeading style={{ fontSize: 14 }}>MMS Fractal Canvas</NavbarHeading>
   401вҶ’          <NavbarDivider />
   402вҶ’          <Tag
   403вҶ’            intent={
   404вҶ’              currentLOD === 'strategic' ? Intent.PRIMARY :
   405вҶ’              currentLOD === 'tactical' ? Intent.WARNING :
   406вҶ’              currentLOD === 'operational' ? Intent.SUCCESS :
   407вҶ’              Intent.DANGER
   408вҶ’            }
   409вҶ’            large
   410вҶ’          >
   411вҶ’            {currentLOD.toUpperCase()}
   412вҶ’          </Tag>
   413вҶ’        </NavbarGroup>
   414вҶ’        <NavbarGroup align={Alignment.RIGHT}>
   415вҶ’          <span style={{ fontSize: 12, marginRight: 8 }}>Zoom: {zoom.toFixed(2)}x</span>
   416вҶ’          <ButtonGroup>
   417вҶ’            <Button icon="minus" onClick={() => handleZoomChange(-0.1)} />
   418вҶ’            <Button icon="plus" onClick={() => handleZoomChange(0.1)} />
   419вҶ’            <Button icon="home" onClick={() => setZoom(initialZoom)} />
   420вҶ’          </ButtonGroup>
   421вҶ’        </NavbarGroup>
   422вҶ’      </Navbar>
   423вҶ’
   424вҶ’      {/* Main content area */}
   425вҶ’      <div style={{ display: 'flex', height: height - 40 }}>
   426вҶ’        {/* Sidebar - Train IDs */}
   427вҶ’        <Card
   428вҶ’          style={{
   429вҶ’            width: 100,
   430вҶ’            height: '100%',
   431вҶ’            borderRadius: 0,
   432вҶ’            padding: 0,
   433вҶ’            overflow: 'hidden',
   434вҶ’          }}
   435вҶ’        >
   436вҶ’          <div style={{ padding: 8, borderBottom: '1px solid #e2e8f0', fontWeight: 600, fontSize: 11 }}>
   437вҶ’            Trains
   438вҶ’          </div>
   439вҶ’          <div style={{ overflowY: 'auto', height: 'calc(100% - 32px)' }}>
   440вҶ’            {visibleTrains.map((train) => (
   441вҶ’              <div
   442вҶ’                key={train.id}
   443вҶ’                style={{
   444вҶ’                  padding: '6px 8px',
   445вҶ’                  borderBottom: '1px solid #f1f5f9',
   446вҶ’                  fontSize: 10,
   447вҶ’                }}
   448вҶ’              >
   449вҶ’                <div style={{ fontWeight: 500 }}>{train.name}</div>
   450вҶ’                <Tag
   451вҶ’                  minimal
   452вҶ’                  intent={train.fleetId === 'kinki' ? Intent.SUCCESS : Intent.PRIMARY}
   453вҶ’                  style={{ fontSize: 9 }}
   454вҶ’                >
   455вҶ’                  {train.fleetId === 'kinki' ? 'KNK' : 'ALT'}
   456вҶ’                </Tag>
   457вҶ’              </div>
   458вҶ’            ))}
   459вҶ’          </div>
   460вҶ’        </Card>
   461вҶ’
   462вҶ’        {/* Canvas area */}
   463вҶ’        <div style={{ flex: 1, position: 'relative' }}>
   464вҶ’          {/* Execution layer (HTML overlay) - only show at execution zoom */}
   465вҶ’          {opacities.execution > 0 && (
   466вҶ’            <ExecutionOverlay
   467вҶ’              tasks={mockData.tasks}
   468вҶ’              trains={mockData.trains}
   469вҶ’              cameraX={cameraX}
   470вҶ’              cameraY={cameraY}
   471вҶ’              zoom={zoom}
   472вҶ’              width={width - 100}
   473вҶ’              height={height - 40}
   474вҶ’              opacity={opacities.execution}
   475вҶ’            />
   476вҶ’          )}
   477вҶ’
   478вҶ’          {/* deck.gl layers for Strategic, Tactical, Operational */}
   479вҶ’          {(opacities.strategic > 0 || opacities.tactical > 0 || opacities.operational > 0) && (
   480вҶ’            <DeckGL
   481вҶ’              width={width - 100}
   482вҶ’              height={height - 40}
   483вҶ’              views={views}
   484вҶ’              viewState={viewState}
   485вҶ’              layers={layers}
   486вҶ’              getCursor={() => 'grab'}
   487вҶ’              style={{ opacity: Math.max(opacities.strategic, opacities.tactical, opacities.operational) }}
   488вҶ’            />
   489вҶ’          )}
   490вҶ’
   491вҶ’          {/* LOD opacity indicators */}
   492вҶ’          <div
   493вҶ’            style={{
   494вҶ’              position: 'absolute',
   495вҶ’              bottom: 16,
   496вҶ’              right: 16,
   497вҶ’              background: 'white',
   498вҶ’              padding: 12,
   499вҶ’              borderRadius: 8,
   500вҶ’              boxShadow: '0 2px 8px rgba(0,0,0,0.15)',
   501вҶ’              fontSize: 11,
   502вҶ’            }}
   503вҶ’          >
   504вҶ’            <div style={{ fontWeight: 600, marginBottom: 8 }}>Layer Visibility</div>
   505вҶ’            <div style={{ display: 'flex', flexDirection: 'column', gap: 4 }}>
   506вҶ’              <div style={{ display: 'flex', alignItems: 'center', gap: 8 }}>
   507вҶ’                <div
   508вҶ’                  style={{
   509вҶ’                    width: 40,
   510вҶ’                    height: 6,
   511вҶ’                    background: `linear-gradient(to right, #3b82f6 ${opacities.strategic * 100}%, #e5e7eb ${opacities.strategic * 100}%)`,
   512вҶ’                    borderRadius: 3,
   513вҶ’                  }}
   514вҶ’                />
   515вҶ’                <span>Strategic ({Math.round(opacities.strategic * 100)}%)</span>
   516вҶ’              </div>
   517вҶ’              <div style={{ display: 'flex', alignItems: 'center', gap: 8 }}>
   518вҶ’                <div
   519вҶ’                  style={{
   520вҶ’                    width: 40,
   521вҶ’                    height: 6,
   522вҶ’                    background: `linear-gradient(to right, #f59e0b ${opacities.tactical * 100}%, #e5e7eb ${opacities.tactical * 100}%)`,
   523вҶ’                    borderRadius: 3,
   524вҶ’                  }}
   525вҶ’                />
   526вҶ’                <span>Tactical ({Math.round(opacities.tactical * 100)}%)</span>
   527вҶ’              </div>
   528вҶ’              <div style={{ display: 'flex', alignItems: 'center', gap: 8 }}>
   529вҶ’                <div
   530вҶ’                  style={{
   531вҶ’                    width: 40,
   532вҶ’                    height: 6,
   533вҶ’                    background: `linear-gradient(to right, #22c55e ${opacities.operational * 100}%, #e5e7eb ${opacities.operational * 100}%)`,
   534вҶ’                    borderRadius: 3,
   535вҶ’                  }}
   536вҶ’                />
   537вҶ’                <span>Operational ({Math.round(opacities.operational * 100)}%)</span>
   538вҶ’              </div>
   539вҶ’              <div style={{ display: 'flex', alignItems: 'center', gap: 8 }}>
   540вҶ’                <div
   541вҶ’                  style={{
   542вҶ’                    width: 40,
   543вҶ’                    height: 6,
   544вҶ’                    background: `linear-gradient(to right, #ef4444 ${opacities.execution * 100}%, #e5e7eb ${opacities.execution * 100}%)`,
   545вҶ’                    borderRadius: 3,
   546вҶ’                  }}
   547вҶ’                />
   548вҶ’                <span>Execution ({Math.round(opacities.execution * 100)}%)</span>
   549вҶ’              </div>
   550вҶ’            </div>
   551вҶ’          </div>
   552вҶ’
   553вҶ’          {/* Zoom slider */}
   554вҶ’          <Card
   555вҶ’            style={{
   556вҶ’              position: 'absolute',
   557вҶ’              bottom: 16,
   558вҶ’              left: 16,
   559вҶ’              padding: 12,
   560вҶ’              width: 200,
   561вҶ’            }}
   562вҶ’          >
   563вҶ’            <div style={{ fontSize: 11, fontWeight: 600, marginBottom: 8 }}>
   564вҶ’              Zoom Level
   565вҶ’            </div>
   566вҶ’            <Slider
   567вҶ’              min={0.1}
   568вҶ’              max={5}
   569вҶ’              stepSize={0.05}
   570вҶ’              value={zoom}
   571вҶ’              onChange={setZoom}
   572вҶ’              labelRenderer={(val) => `${val.toFixed(1)}x`}
   573вҶ’              labelStepSize={1}
   574вҶ’            />
   575вҶ’            <div style={{ fontSize: 10, color: '#666', marginTop: 8 }}>
   576вҶ’              <div>Strategic: &lt; 0.3x</div>
   577вҶ’              <div>Tactical: 0.3 - 1.0x</div>
   578вҶ’              <div>Operational: 1.0 - 3.0x</div>
   579вҶ’              <div>Execution: &gt; 3.0x</div>
   580вҶ’            </div>
   581вҶ’          </Card>
   582вҶ’        </div>
   583вҶ’      </div>
   584вҶ’    </div>
   585вҶ’  );
   586вҶ’};
   587вҶ’
   588вҶ’// =============================================================================
   589вҶ’// EXECUTION OVERLAY (HTML-based for detailed view)
   590вҶ’// =============================================================================
   591вҶ’
   592вҶ’interface ExecutionOverlayProps {
   593вҶ’  tasks: Task[];
   594вҶ’  trains: Train[];
   595вҶ’  cameraX: number;
   596вҶ’  cameraY: number;
   597вҶ’  zoom: number;
   598вҶ’  width: number;
   599вҶ’  height: number;
   600вҶ’  opacity: number;
   601вҶ’}
   602вҶ’
   603вҶ’const ExecutionOverlay: React.FC<ExecutionOverlayProps> = ({
   604вҶ’  tasks,
   605вҶ’  trains,
   606вҶ’  cameraX,
   607вҶ’  cameraY,
   608вҶ’  zoom,
   609вҶ’  width,
   610вҶ’  height,
   611вҶ’  opacity,
   612вҶ’}) => {
   613вҶ’  const ROW_HEIGHT = 80;
   614вҶ’  const EXEC_PX_PER_DAY = 80;
   615вҶ’  const HEADER_HEIGHT = 50;
   616вҶ’
   617вҶ’  // Filter tasks for visible range
   618вҶ’  const visibleTasks = useMemo(() => {
   619вҶ’    const startTrain = Math.max(0, Math.floor(cameraY));
   620вҶ’    const endTrain = Math.min(trains.length - 1, Math.ceil(cameraY + height / ROW_HEIGHT));
   621вҶ’
   622вҶ’    return tasks.filter((task) => {
   623вҶ’      return task.trainIndex >= startTrain && task.trainIndex <= endTrain;
   624вҶ’    }).slice(0, 50); // Limit for performance
   625вҶ’  }, [tasks, trains.length, cameraY, height]);
   626вҶ’
   627вҶ’  // Calculate earliest task day
   628вҶ’  const earliestTaskDay = useMemo(() => {
   629вҶ’    if (visibleTasks.length === 0) return 0;
   630вҶ’    const days = visibleTasks.map(t => daysBetween(TIME_RANGE.start, t.startDate));
   631вҶ’    return Math.min(...days);
   632вҶ’  }, [visibleTasks]);
   633вҶ’
   634вҶ’  return (
   635вҶ’    <div
   636вҶ’      style={{
   637вҶ’        position: 'absolute',
   638вҶ’        top: 0,
   639вҶ’        left: 0,
   640вҶ’        width,
   641вҶ’        height,
   642вҶ’        overflow: 'hidden',
   643вҶ’        background: '#f8fafc',
   644вҶ’        opacity,
   645вҶ’        pointerEvents: opacity > 0.5 ? 'auto' : 'none',
   646вҶ’      }}
   647вҶ’    >
   648вҶ’      {/* Header */}
   649вҶ’      <div
   650вҶ’        style={{
   651вҶ’          position: 'absolute',
   652вҶ’          top: 0,
   653вҶ’          left: 0,
   654вҶ’          right: 0,
   655вҶ’          height: HEADER_HEIGHT,
   656вҶ’          background: 'white',
   657вҶ’          borderBottom: '1px solid #e2e8f0',
   658вҶ’          display: 'flex',
   659вҶ’          alignItems: 'center',
   660вҶ’          paddingLeft: 16,
   661вҶ’          fontWeight: 600,
   662вҶ’          fontSize: 12,
   663вҶ’        }}
   664вҶ’      >
   665вҶ’        Execution View - {visibleTasks.length} tasks visible
   666вҶ’      </div>
   667вҶ’
   668вҶ’      {/* Task cards */}
   669вҶ’      <div
   670вҶ’        style={{
   671вҶ’          position: 'absolute',
   672вҶ’          top: HEADER_HEIGHT,
   673вҶ’          left: 0,
   674вҶ’          right: 0,
   675вҶ’          bottom: 0,
   676вҶ’          overflow: 'auto',
   677вҶ’        }}
   678вҶ’      >
   679вҶ’        {visibleTasks.map((task) => {
   680вҶ’          const startDay = daysBetween(TIME_RANGE.start, task.startDate);
   681вҶ’          const duration = Math.max(1, daysBetween(task.startDate, task.endDate));
   682вҶ’          const dayOffset = startDay - earliestTaskDay;
   683вҶ’
   684вҶ’          const x = 16 + dayOffset * EXEC_PX_PER_DAY;
   685вҶ’          const y = (task.trainIndex - Math.floor(cameraY)) * ROW_HEIGHT + 10;
   686вҶ’          const w = Math.max(duration * EXEC_PX_PER_DAY - 10, 150);
   687вҶ’
   688вҶ’          const mt = MAINTENANCE_TYPE_MAP.get(task.type);
   689вҶ’
   690вҶ’          return (
   691вҶ’            <Card
   692вҶ’              key={task.id}
   693вҶ’              interactive
   694вҶ’              elevation={1}
   695вҶ’              style={{
   696вҶ’                position: 'absolute',
   697вҶ’                left: x,
   698вҶ’                top: y,
   699вҶ’                width: w,
   700вҶ’                height: 60,
   701вҶ’                padding: 8,
   702вҶ’                borderLeft: `4px solid ${mt?.color ?? '#94a3b8'}`,
   703вҶ’                overflow: 'hidden',
   704вҶ’              }}
   705вҶ’            >
   706вҶ’              <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'flex-start', marginBottom: 4 }}>
   707вҶ’                <div style={{ fontSize: 10, fontWeight: 600, color: '#1e293b' }}>
   708вҶ’                  {task.name}
   709вҶ’                </div>
   710вҶ’                <Tag
   711вҶ’                  minimal
   712вҶ’                  intent={
   713вҶ’                    task.status === 'completed' ? Intent.SUCCESS :
   714вҶ’                    task.status === 'in-progress' ? Intent.PRIMARY :
   715вҶ’                    task.status === 'overdue' ? Intent.DANGER :
   716вҶ’                    Intent.NONE
   717вҶ’                  }
   718вҶ’                  style={{ fontSize: 8 }}
   719вҶ’                >
   720вҶ’                  {task.status}
   721вҶ’                </Tag>
   722вҶ’              </div>
   723вҶ’              <div style={{ fontSize: 9, color: '#64748b' }}>
   724вҶ’                {task.durationHours}h вҖў {task.manHours}mh
   725вҶ’              </div>
   726вҶ’              {task.hasConflict && (
   727вҶ’                <Tag intent={Intent.DANGER} style={{ position: 'absolute', top: 4, right: 4, fontSize: 8 }}>!</Tag>
   728вҶ’              )}
   729вҶ’            </Card>
   730вҶ’          );
   731вҶ’        })}
   732вҶ’      </div>
   733вҶ’    </div>
   734вҶ’  );
   735вҶ’};
   736вҶ’
   737вҶ’export default FractalCanvas;
   738вҶ’

